import{_ as r,c as p,o as t,a as b}from"./app.015fbf38.js";const f='{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E8C\u7AE0","description":"","frontmatter":{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E8C\u7AE0","date":"2018-05-30T06:40:35.000Z","categories":["\u8B80\u7D93\u7D00\u9304"]},"headers":[],"relativePath":"Bike/BikeTravel/20180528_\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E8C\u7AE0.md","lastUpdated":1648513476165}',e={},a=b('<p><img src="https://farm2.staticflickr.com/1755/27550177507_89821ce89a_k.jpg" alt=""></p><p>\u672C\u7AE0\u4E00\u958B\u59CB\uFF0C\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u505A\u4E86\u5922\uFF0C\u5C0E\u81F4\u7761\u4E0D\u597D\u5931\u7720<br> \u65BC\u662F\u738B\u5C31\u53EC\u96C6\u990A\u5175\u591A\u65E5\u7684\u8853\u58EB\u9032\u5BAE\uFF0C\u770B\u662F\u5426\u80FD\u89E3\u5922<br> \u53EF\u80FD\u738B\u534A\u5922\u534A\u9192\u72C0\u614B\uFF0C\u5FD8\u8A18\u5922\u5883\u5167\u5BB9\u4E5F\u60F3\u85C9\u6A5F\u8003\u8003\u8853\u58EB<br></p><p>\u8853\u58EB\u7167\u4EE5\u5F80\u6163\u4F8B\uFF0C\u5206\u6790\u5922\u5883\u6642\u9700\u8981\u7576\u4E8B\u4EBA\u63D0\u4F9B\u9EDE\u7DDA\u7D22<br> \u4F46\u738B\u504F\u504F\u5C31\u662F\u5FD8\u4E86\uFF0C\u8853\u58EB\u5C31\u4E00\u518D\u8ACB\u6C42\u738B\u900F\u9732\u4E9B\u5167\u5BB9<br> \u738B\u77E5\u9053\u53EA\u8981\u8B1B\u51FA\u4E9B\u5167\u5BB9\uFF0C\u8853\u58EB\u6709\u8FA6\u6CD5\u8B1B\u5F97\u4F3C\u662F\u800C\u975E<br> \u4F46\u738B\u8A8D\u70BA\uFF0C\u8853\u58EB\u60F3\u63A1\u7528\u62D6\u5EF6\u6230\u8853<br> \u5149\u662F\u8B1B\u4E9B\u5949\u627F\u7684\u8A71\u5C31\u80FD\u6253\u6DF7\u904E\u53BB<br> \u5728\u8A0E\u50F9\u9084\u50F9\u4E2D\uFF0C\u751A\u81F3\u6709\u9EDE\u60F1\u7F9E\u6210\u6012<br> \u4FBF\u4E0B\u4EE4\u5373\u523B\u6D88\u6EC5\u6240\u6709\u5DF4\u6BD4\u502B\u54F2\u58EB</p><p>\u4F46\u4EE5\u7406\u5F9E\u9019\u7AE0\u958B\u59CB\u5C55\u9732\u982D\u89D2\uFF0C\u4E5F\u80FD\u770B\u51FA\u500B\u4EBA\u7279\u8CEA\u986F\u660E<br> \u6574\u7406\u4E00\u4E0B\uFF0C\u672C\u7AE0\u5F8C\u7E8C\u7684\u767C\u5C55\uFF0C\u6B78\u7D0D\u51FA\u4F46\u4EE5\u7406\u7684\u7279\u8CEA\u5982\u4E0B\uFF1A</p><ol><li><p>\u4F46\u4EE5\u7406\u5728\u7687\u5BAE\u4E2D\u662F\u6C92\u6C92\u7121\u805E\u7684\u4EBA<br> \u738B\u4E0B\u4EE4\u8981\u6BBA\u6389\u6240\u6709\u5DF4\u6BD4\u502B\u7684\u54F2\u58EB\u6642\uFF0C\u4F46\u4EE5\u7406\u53EF\u80FD\u4E0D\u77E5\u9053\u9019\u4EF6\u4E8B<br> \u5F9EV2.16\u4F46\u4EE5\u7406\u7684\u53CD\u61C9\u770B\u51FA\uFF0C\u4E5F\u6709\u53EF\u80FD\u9019\u6642\u9084\u5728\u7687\u5BAE\u53D7\u8A13\u672A\u6EFF\u4E09\u5E74<br> \u4E5F\u6709\u53EF\u80FD\u4F46\u4EE5\u7406\u9084\u662F\u4E00\u500B\u4E73\u81ED\u672A\u4E7E\u7684\u9752\u5E74\u4EBA\uFF0C\u4E26\u672A\u53D7\u5230\u91CD\u8996</p></li><li><p>\u4F46\u4EE5\u7406EQ\u5F88\u9AD8\uFF0C\u81E8\u5371\u4E0D\u4E82\u8655\u8B8A\u4E0D\u9A5A<br> \u7576\u4F46\u4EE5\u7406\u63A5\u53D7\u5230\u81EA\u5DF1\u4E5F\u5728\u6BBA\u622E\u540D\u55AE\u4E2D\u4E26\u672A\u611F\u5230\u5BB3\u6015<br> \u53CD\u800C\u6025\u4E2D\u751F\u667A\uFF0C\u81EA\u9042\u898B\u738B\u6C42\u5BEC\u5BB9\u6642\u9593\uFF0C\u4E26\u80FD\u70BA\u738B\u89E3\u5922<br> \u4E0D\u77E5\u738B\u7684\u5FC3\u614B\u5982\u4F55\uFF0C\u4E0D\u904E\u53EF\u80FD\u62B1\u8457\u59D1\u4E14\u8A66\u8A66\u7684\u5FC3\u614B\u5148\u7B54\u61C9<br> \u800C\u9019\u7AE0\u88E1\u9762\u4E5F\u6C92\u6709\u770B\u5230\u4F46\u4EE5\u7406\u7D72\u6BEB\u6709\u9732\u51FA\u5BB3\u6015\u7684\u6C23\u606F<br> \u9802\u591A\u53EA\u770B\u5230\u4F46\u4EE5\u7406\u8207\u4E09\u4F4D\u540C\u4F34\u540C\u5FC3\u5408\u4E00\u5411\u795E\u4E5E\u6C42</p></li><li><p>\u4F46\u4EE5\u7406\u5C0D\u795E\u6709\u4FE1\u5FC3\uFF0C\u76F8\u4FE1\u795E\u6703\u7D66\u4ED6\u89E3\u5922\u5883\u7684\u80FD\u529B<br> \u5F9E\u9019\u7AE0\u7684\u6642\u9593\u6F14\u9032\u4F86\u770B\uFF0C\u4F46\u4EE5\u7406\u5148\u6C42\u738B\uFF0C\u518D\u56DE\u4F86\u6C42\u795E<br> \u7576\u4ED6\u5411\u738B\u63D0\u51FA\u5BEC\u9650\u8ACB\u6C42\u6642\uFF0C\u738B\u6240\u7B54\u61C9\u7684\u6642\u7A0B\u4E5F\u61C9\u8A72\u4E0D\u6703\u592A\u4E45<br> \u7562\u7ADF\u738B\u5DF2\u7D93\u6025\u5230\u4E0B\u4EE4\u8981\u6BBA\u6389\u6240\u6709\u7684\u8853\u58EB<br> \u800C\u4F46\u4EE5\u7406\u4E5F\u80F8\u6709\u6210\u8DB3\uFF0C\u56DE\u982D\u518D\u627E\u5925\u4F34\u4E00\u8D77\u79B1\u544A\u7948\u6C42\u4E0A\u5E1D<br> \u4E0A\u5E1D\u4E5F\u5F88\u4FE1\u5BE6\uFF0C\u5728\u591C\u9593\u5C07\u5922\u5883\u53CA\u5922\u5883\u610F\u6DB5\u986F\u660E</p></li><li><p>\u4F46\u4EE5\u7406\u4E0D\u5C45\u529F\uFF0C\u4EE5\u795E\u70BA\u5927\uFF0C\u4E5F\u70BA\u670B\u53CB\u8B00\u798F\u5229<br> \u4F46\u4EE5\u7406\u89E3\u5922\u6642\uFF0C\u5148\u8B1B\u51FA\u9019\u662F\u4E0A\u5E1D\u7D66\u4ED6\u986F\u660E\u5967\u7955\u7684\u4E8B<br> \u662F\u795E\u80FD\u529B\u7684\u5F70\u986F\uFF0C\u4ED6\u624D\u80FD\u9806\u5229\u89E3\u5922<br> \u4F46\u4EE5\u7406\u89E3\u5B8C\u5922\u5883\u6642\uFF0C\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u4FEF\u4F0F\u5728\u5730\uFF0C\u5411\u4F46\u4EE5\u7406\u4E0B\u62DC<br> \u6D3E\u4ED6\u7BA1\u7406\u5DF4\u6BD4\u502B\u5168\u7701\uFF0C\u53C8\u7ACB\u4ED6\u70BA\u7E3D\u7406<br> \u6700\u5F8C\u4F46\u4EE5\u7406\u4E5F\u70BA\u670B\u53CB\u6C42\uFF0C\u5176\u4E09\u4F4D\u670B\u53CB\u4E5F\u7BA1\u7406\u5DF4\u6BD4\u502B\u7701\u7684\u4E8B\u52D9</p></li></ol><p>\u6700\u5F8C\u6709\u5E7E\u500B\u554F\u984C\u662F\u81EA\u5DF1\u60F3\u50CF\u7684\uFF0C\u4E0D\u78BA\u5B9A\u771F\u5BE6\u60C5\u6CC1\u662F\u5426\u9019\u6A23</p><ol><li><p>\u738B\u70BA\u4F55\u80FD\u63A5\u6536\u4F46\u4EE5\u7406\u7684\u8ACB\u6C42\uFF0C\u4E0D\u5201\u96E3\u4ED6<br> \u53EF\u80FD\u7576\u6642\u4F46\u4EE5\u7406\u5F88\u5E74\u8F15(\u63A8\u6E2C\u672A\u6EFF20)\uFF0C\u5728\u738B\u7684\u773C\u88E1\u4E0D\u8DB3\u70BA\u61FC<br> \u65E2\u7136\u671D\u4E2D\u7684\u8853\u58EB\u90FD\u6C92\u8FA6\u6CD5\uFF0C\u59D1\u4E14\u8A66\u8A66\u63A5\u53D7\u4ED6\u7684\u5EFA\u8B70<br> \u4E0D\u904E\u671F\u9650\u61C9\u8A72\u6703\u5F88\u77ED\uFF0C\u53EF\u80FD\u4E00\u5169\u5929\u5167\uFF0C\u76F8\u7576\u77ED\u7684\u671F\u9650<br> \u6240\u4EE5\u795E\u7576\u591C\u5C31\u7D66\u89E3\u5922\u7684\u667A\u6167\uFF0C\u8B93\u4ED6\u9694\u5929\u80FD\u9806\u5229\u70BA\u738B\u8B1B\u89E3</p></li><li><p>\u4F46\u4EE5\u7406\u70BA\u540C\u4F34\u8B00\u6C42\u5B98\u4F4D\uFF0C\u662F\u4E3B\u52D5\u7684\u9084\u662F\u88AB\u52D5\u7684?<br> V2.48\u770B\u5230\u5148\u662F<span style="color:red;">\u738B\u6D3E\u4ED6\u7BA1\u7406\u5DF4\u6BD4\u502B\u5168\u7701</span><br> V2.49\u624D\u63D0\u5230\uFF0C\u5728<span style="color:red;">\u4F46\u4EE5\u7406\u6C42\u738B</span>\u5F8C<br> \u5176\u4ED6\u4E09\u4F4D\u670B\u53CB\u624D\u6709\u7BA1\u7406\u5DF4\u6BD4\u502B\u7701\u7684\u4E8B\u52D9\u7684\u8077\u4F4D<br> \u5F9E\u5B57\u9762\u4E0A\u7684\u610F\u601D\u4F86\u770B\uFF0C\u4E5F\u53EF\u4EE5\u89E3\u91CB\u6210<br><span style="color:blue;">\u4F46\u4EE5\u7406\u5C07\u7BA1\u7406\u5DF4\u6BD4\u502B\u7684\u8077\u4F4D\u7559\u7D66\u4E09\u4F4D\u597D\u53CB</span><br> \u7136\u5F8C\u81EA\u5DF1\u9078\u64C7\u7E7C\u7E8C<span style="color:red;">\u5728\u671D\u4E2D\u4F8D\u7ACB</span>\uFF0C\u5F85\u5728\u738B\u7684\u8EAB\u908A<br> \u9019\u908A\u89E3\u91CB\u6210\u4F46\u4EE5\u7406\u4E0D\u60F3\u5B98\u4F4D\uFF0C\u628A\u5B83\u8B93\u7D66\u5176\u4ED6\u4E09\u4F4D\u597D\u53CB<br> \u9019\u6A23\u63A5<strong><span style="color:red;">\u53EA\u662F</span>\u4F46\u4EE5\u7406\u5E38\u5728\u671D\u4E2D\u4F8D\u7ACB</strong>\uFF0C\u8F03\u5408\u7406</p></li><li><p>\u4F46\u4EE5\u7406\u89E3\u5922\u7684\u80FD\u529B\uFF0C\u662F\u4EE5\u524D\u5C31\u6709\uFF0C\u9084\u662F\u5F8C\u4F86\u624D\u6709?<br> \u5F9E\u9019\u7AE0\u4E5F\u96E3\u770B\u51FA\uFF0C\u5C31\u662F\u4F46\u4EE5\u7406\u89E3\u5922\u80FD\u529B\u662F\u7576\u591C\u795E\u624D\u7D66<br> \u9084\u662F\u5148\u524D\u4ED6\u5C31\u6709\u80FD\u529B\u53EF\u4EE5\u89E3\u5922\uFF0C\u53EA\u662F\u53EF\u80FD\u672A\u958B\u767C<br> \u9019\u908A\u6211\u50BE\u5411\u4F46\u4EE5\u7406\u539F\u672C\u5C31\u6709\u89E3\u5922\u7684\u80FD\u529B<br> \u4E3B\u8981\u662F\u5C0D\u7167<span style="color:red;">V1.17\u4F46\u4EE5\u7406\u53C8\u660E\u767D\u5404\u6A23\u7684\u7570\u8C61\u548C\u5922\u5146</span><br> \u53EF\u80FD\u50CF\u7D04\u745F\u4E00\u6A23\uFF0C\u7D04\u745F\u5C0F\u6642\u5019\u5C31\u505A\u904E\u7570\u5922<br> \u7B49\u5230\u9577\u5927\uFF0C\u5728\u76E3\u7344\u4E2D\u53EF\u4EE5\u5E6B\u5176\u4ED6\u4EBA\u89E3\u5922<br> \u6216\u8A31\u4F46\u4EE5\u7406\u5728\u9019\u4E4B\u524D\u6709\u89E3\u5922\u80FD\u529B\uFF0C\u53EA\u662F\u6C92\u6709\u88AB\u6316\u6398</p></li></ol><p>\u4EE5\u4E0A\u662F\u500B\u4EBA\u63A8\u6E2C\uFF0C\u89E3\u7D93\u662F\u5F88\u4E3B\u89C0\u7684\uFF0C\u6C92\u6709\u6240\u8B02\u7684\u5C0D\u932F<br> \u4E5F\u53EF\u4EE5\u7528\u6B64\u65B9\u5F0F\u52FE\u52D2\u51FA\u4F46\u4EE5\u7406\u7684\u7279\u8CEA\u8207\u6027\u683C</p><p><img src="https://farm2.staticflickr.com/1752/42419769142_1d060a3cc4.jpg" alt=""></p>',9),s=[a];function l(o,_,c,i,n,d){return t(),p("div",null,s)}var g=r(e,[["render",l]]);export{f as __pageData,g as default};
